const { sortVersions } = require('./src/core/versions');

// Test cases from conventions.md
const cases = [
  // numeric core: 1.10.0 > 1.2.0
  { input: ['1.2.0', '1.10.0', '1.1.0'], expected: ['1.1.0', '1.2.0', '1.10.0'] },
  // pre-release < release
  { input: ['1.0.0', '1.0.0-rc.1'], expected: ['1.0.0-rc.1', '1.0.0'] },
  // pre-release field ordering: alpha.2 < alpha.10
  { input: ['1.0.0-alpha.10', '1.0.0-alpha.2'], expected: ['1.0.0-alpha.2', '1.0.0-alpha.10'] },
  // lexical: alpha < rc
  { input: ['1.0.0-rc', '1.0.0-alpha'], expected: ['1.0.0-alpha', '1.0.0-rc'] },
  // more fields = higher: alpha < alpha.1
  { input: ['1.0.0-alpha.1', '1.0.0-alpha'], expected: ['1.0.0-alpha', '1.0.0-alpha.1'] },
  // build metadata ignored for sort, preserved in output
  { input: ['1.0.0+build.9', '1.0.0+build.5'], expected: ['1.0.0+build.9', '1.0.0+build.5'] },
  // numeric identifier < alphanumeric (SemVer spec: numeric has lower precedence)
  { input: ['1.0.0-alpha', '1.0.0-1'], expected: ['1.0.0-1', '1.0.0-alpha'] },
];

let allPassed = true;
cases.forEach(({ input, expected }, i) => {
  const result = sortVersions(input);
  const pass = JSON.stringify(result) === JSON.stringify(expected);
  if (!pass) {
    console.log('FAIL case', i, ':', JSON.stringify(result), '!=', JSON.stringify(expected));
    allPassed = false;
  }
});

// Verify input not mutated
const arr = ['1.0.0', '2.0.0', '0.1.0'];
const orig = arr.slice();
sortVersions(arr);
if (JSON.stringify(arr) !== JSON.stringify(orig)) {
  console.log('FAIL: input mutated');
  allPassed = false;
}

if (allPassed) console.log('All tests passed');
